from .constants import MOD

def add(a, b):
    """Add two integers a and b modulo MOD."""
    return (a + b) % MOD

def mul(a, b):
    """Compute the product of two integers a and b modulo MOD."""
    return (a * b) % MOD

def binpow(a, b):
    """Compute modular exponentiation a^b mod MOD."""
    result = 1
    a = a % MOD
    while b > 0:
        if b % 2 == 1:
            result = mul(result, a)
        a = mul(a, a)
        b //= 2
    return result

def get_primes(d):
    """Factorize integer d and return dict of prime factors with exponents."""
    factors = {}
    i = 2
    temp = d
    while i * i <= temp:
        while temp % i == 0:
            factors[i] = factors.get(i, 0) + 1
            temp //= i
        i += 1
    if temp > 1:
        factors[temp] = factors.get(temp, 0) + 1
    return factors

def get_factorials(n):
    """Precompute factorials and their modular inverses up to n."""
    fact = [1] * (n + 1)
    inv_fact = [1] * (n + 1)
    for i in range(1, n + 1):
        fact[i] = mul(fact[i - 1], i)
    inv_fact[n] = binpow(fact[n], MOD - 2)
    for i in range(n - 1, -1, -1):
        inv_fact[i] = mul(inv_fact[i + 1], i + 1)
    return fact, inv_fact

def multinomial(exponents, fact, inv_fact):
    """Compute multinomial coefficient."""
    total = sum(exponents)
    if total == 0:
        return 1
    result = fact[total]
    for e in exponents:
        if e > 0:
            result = mul(result, inv_fact[e])
    return result

def gcd(a, b):
    """Compute GCD of two numbers."""
    while b:
        a, b = b, a % b
    return a

