    prime_factors = get_primes(D)
    primes = list(prime_factors.keys())
    num_primes = len(primes)
    max_n = num_primes + 10
    fact, inv_fact = get_factorials(max_n)
    results = []
    for v, u in queries:
        if v == u:
            results.append(1)
            continue
        v_factors = get_primes(v)
        u_factors = get_primes(u)
        steps = []
        for p in primes:
            exp_v = v_factors.get(p, 0)
            exp_u = u_factors.get(p, 0)
            diff = abs(exp_v - exp_u)
            if diff > 0:
                steps.append(diff)
        total_steps = sum(steps)
        if total_steps == 0:
            results.append(1)
        else:
            result = multinomial(steps, fact, inv_fact)
            results.append(result)
    return results
